import json
for name in ['baseline-packages.json', 'after-cpm-packages.json']:
    with open(name) as f:
        content = f.read()
    # Handle NDJSON
    lines = [l for l in content.strip().split('\n') if l.strip()]
    for line in lines:
        d = json.loads(line)
        if 'projects' in d:
            for p in d['projects']:
                for fw in p.get('frameworks', []):
                    for pkg in fw.get('topLevelPackages', []):
                        print(f'{name}: {p[\"path\"].split(\"/\")[-1]} -> {pkg[\"id\"]} {pkg.get(\"requestedVersion\",\"\")} resolved={pkg.get(\"resolvedVersion\",\"\")}')
"

